:null,"expires_at":null,"days_remaining":null}},{"uuid":"a87b5a4e-ed78-49e5-a7a6-f2c7e76bc3d1","first_name":"Omar","last_name":"Soukarieh","roles":["Expert"],"additional_permissions":[],"institution":"Institut National de la Santé et de la Recherche Médicale (INSERM)","credentials":["PhD"],"code_of_conduct":{"status":"current","current_version":"1.0.0","completed_at":"2026-03-30T11:34:10+00:00","expires_at":"2027-03-30T11:34:10+00:00","days_remaining":357}},{"uuid":"7d922e49-29e4-4f23-aea0-d085f79d21dc","first_name":"Zahra","last_name":"Saadat","roles":["Expert"],"additional_permissions":[],"institution":"University of North Carolina at Chapel Hill","credentials":["CGC"],"code_of_conduct":{"status":"current","current_version":"1.0.0","completed_at":"2026-03-30T20:16:57+00:00","expires_at":"2027-03-30T20:16:57+00:00","days_remaining":358}}],"expert_panel":{"uuid":"bfc90200-6e33-4675-94c2-f6addedad612","affiliation_id":"50037","name":"Hereditary Hemorrhagic Telangiectasia","short_name":"HHT","scope_description":"Pathogenic germline variants in ACVRL1, ENG, and SMAD4 are associated with hereditary hemorrhagic telangiectasia (HHT, MIM: 600376, 187300) and juvenile polyposis syndrome/HHT (JPS/HHT, MIM: 175050). HHT is an autosomal dominant vascular dysplasia characterized by small vascular lesions (telangiectases) and larger vascular lesions (arteriovenous malformations (AVMs)) in characteristic locations (telangiectases in the oral and nasal mucosa, lips, fingers, upper intestinal tract; AVMs in the lungs, liver and brain). This expert panel will provide assessment regarding the pathogenicity of variants in ACVRL1, ENG, and SMAD4 with respect to HHT disease. Specifically, we will develop a set of HHT rule specifications of the ACMG/AMP guidelines with individual gene specifications where needed. We will first focus our efforts on curating variants that are currently in ClinVar, and then we will expand our efforts to curating variants from other HHT databases and submit those to ClinVar.","membership_description":null,"type":"vcep","date_completed":"2024-02-29T05:00:00.000000Z","inactive_date":null,"current_step":4,"all_genes":[{"hgnc_id":3349,"gene_symbol":"ENG","mondo_id":"MONDO:0008535","disease_name":"telangiectasia, hereditary hemorrhagic, type 1","disease_entity":null},{"hgnc_id":175,"gene_symbol":"ACVRL1","mondo_id":"MONDO:0010880","disease_name":"telangiectasia, hereditary hemorrhagic, type 2","disease_entity":null},{"hgnc_id":6770,"gene_symbol":"SMAD4","mondo_id":"MONDO:0008278","disease_name":"juvenile polyposis/hereditary hemorrhagic telangiectasia syndrome","disease_entity":null}],"clinvar_org_id":"509488","vcep_definition_approval":"2019-02-06T05:00:00.000000Z","vcep_draft_specification_approval":"2022-07-15T04:00:00.000000Z","vcep_pilot_approval":"2023-09-01T04:00:00.000000Z","vcep_final_approval":"2024-02-29T05:00:00.000000Z"},"parent":{"uuid":"ceb37cbb-cccd-44fd-b309-82d863b25f9b","name":"Hemostasis/Thrombosis","type":"cdwg","status":"active"}}}

{"event_type":"group_checkpoint_event","schema_version":"2.0.1","date":"2026-04-06 17:41:15","data":{"uuid":"1f4a5fb5-b3ba-43df-a372-7789c0e16f46","name":"Phenylketonuria","description":"Phenylketonuria (PKU; OMIM #261600), also referred to as phenylalanine hydroxylase (PAH)*&#x20;*&#x64;eficiency, is an inherited metabolic genetic condition caused by biallelic pathogenic variants in the *PAH&#x20;*&#x67;ene. PKU is characterized by the accumulation of phenylalanine and decreased tyrosine levels. The carrier frequency varies throughout the world, but is approximately 1/50 ([*NHS North Bristol, 2020*](https://www.nbt.nhs.uk/sites/default/files/Phenylketonuria%20%28PKU%29%20.pdf)).

Phenotypes of this condition include: PAH deficiency treated from birth, late-diagnosed/untreated PAH deficiency, and Maternal phenylketonuria syndrome (MPKU). Newborns affected by PKU can initially appear asymptomatic, but symptoms will start after a few months; symptoms include: musty odor, fair skin, eczema, seizures, tremors, and hyperactivity. Symptom severity will vary based on age of treatment and the alleles (mild/severe) ([*Stone WL et al., 2023*](https://www.ncbi.nlm.nih.gov/books/NBK535378/)). MPKU may cause fetal brain damage and congenital heart disease, regardless of if the fetus has PKU. ([*Prick BW et al., 2012*](https://pubmed.ncbi.nlm.nih.gov/22205310/))

The expert panel was Step 4 approved for sustained curation in 2018 and is currently prioritizing the curation of ClinVar variants with conflicting classifications. As of January 2026, around 800  variants have been curated/submitted to ClinVar; variants that are curated to likely pathogenic or uncertain significance require regular recuration on ClinGen’s approved timeline (2 years). Members of this panel are experts in the research, clinical, and biochemical aspects of phenylketonuria and other inborn errors of metabolism. Our goal is to examine PAH variants by their pathogenicity to benefit earlier diagnosis and patient care.","caption":null,"icon_url":null,"status":"active","status_date":"2022-02-14T23:47:01+00:00","type":"vcep","coi":"https://gpm.clinicalgenome.org/coi-group/1f4a5fb5-b3ba-43df-a372-7789c0e16f46","members":[{"uuid":"89bcda21-1e77-4d4d-9be1-56a47c93243c","first_name":"Meredith","last_name":"Weaver","roles":["Coordinator","Grant Liaison"],"additional_permissions":["info-edit","members-invite","members-retire","members-remove","members-update","application-read","application-edit"],"institution":"American College of Medical Genetics & Genomics","credentials":["PhD","CGC"],"code_of_conduct":{"status":"current","current_version":"1.0.0","completed_at":"2026-03-16T12:37:24+00:00","expires_at":"2027-03-16T12:37:24+00:00","days_remaining":343},"profile_photo":"https://gpm.clinicalgenome.org/profile-photos/CxaI5tlZwuGY40GUJvwyMRcNLZEoDE3JHGOVrxK8.png","email":"mweaver@acmg.net"},{"uuid":"67c2f22c-f4d0-4c48-b96f-372795f3a3ee","first_name":"Raquel","last_name":"Fernandez","roles":["Coordinator"],"additional_permissions":[],"institution":"American College of Medical Genetics & Genomics","credentials":["BSc"],"code_of_conduct":{"status":"current","current_version":"1.0.0","completed_at":"2026-03-12T15:12:19+00:00","expires_at":"2027-03-12T15:12:19+00:00","days_remaining":339},"profile_photo":"https://gpm.clinicalgenome.org/profile-photos/6umcflmvuasOXxSJdZMw