19:16:38+00:00","days_remaining":344},"email":"wilta@ad.unc.edu"},{"uuid":"92707b51-46dc-4471-a748-f642c79a412d","first_name":"Kavini","last_name":"Nanayakkara","roles":["Biocurator"],"additional_permissions":[],"institution":"Mayo Clinic  Rochester","credentials":["MSc"],"code_of_conduct":{"status":"missing","current_version":"1.0.0","completed_at":null,"expires_at":null,"days_remaining":null}},{"uuid":"c8f9667f-8216-4b55-aa85-d44c3a477e36","first_name":"Xiang Li","last_name":"Zhang","roles":["Biocurator"],"additional_permissions":[],"institution":"self-employed","credentials":["BSc"],"code_of_conduct":{"status":"missing","current_version":"1.0.0","completed_at":null,"expires_at":null,"days_remaining":null}},{"uuid":"9d39fb5a-462e-428d-8a65-18b655dd3405","first_name":"Sadhana","last_name":"Gollapudi","roles":["Biocurator"],"additional_permissions":[],"institution":"Alcon","credentials":["PhD"],"code_of_conduct":{"status":"missing","current_version":"1.0.0","completed_at":null,"expires_at":null,"days_remaining":null}}],"expert_panel":{"uuid":"10611c1c-a9f2-4009-80e4-f8504c955045","affiliation_id":"50064","name":"Thrombosis","short_name":"Thrombosis","scope_description":"The Thrombosis VCEP plan to focus on curation of genes associated with Mendelian non-syndromic risk of venous thrombosis, such as protein S and C deficiencies, antithrombin deficiency (formerly antithrombin III deficiency), activated protein C resistance related to F5 and prothrombin. The VCEP will initially focus on SERPINC1 gene, associated with antithrombin deficiency, as this gene is one of the more sequenced genes for during a thrombophilia workup. We plan to move on to PROS1 and PROC to evaluate protein S and C deficiencies, respectively. As more pathogenic variants have been identified in the F5 and F2 genes related to thrombophilia risk, it will also be important to evaluate these genes for pathogenic variants in addition to the well described Factor V Leiden and Prothrombin variants.

The VCEP plans to meet monthly to begin specifying the ACMG/AMP Variant Curation Guidelines for SERPINC1. Once rule specifications are complete, we will then focus on PROS1 and PROC, which may only require minor tweaks in rule specifications due to the similar phenotype.","membership_description":null,"type":"vcep","date_completed":"2023-06-16T04:00:00.000000Z","inactive_date":null,"current_step":4,"all_genes":[{"hgnc_id":775,"gene_symbol":"SERPINC1","mondo_id":"MONDO:0013144","disease_name":"hereditary antithrombin deficiency","disease_entity":null},{"hgnc_id":9451,"gene_symbol":"PROC","mondo_id":"MONDO:0008560","disease_name":"thrombophilia due to activated protein C resistance","disease_entity":null}],"clinvar_org_id":"509282","vcep_definition_approval":"2020-03-16T04:00:00.000000Z","vcep_draft_specification_approval":"2021-03-01T05:00:00.000000Z","vcep_pilot_approval":"2023-05-10T04:00:00.000000Z","vcep_final_approval":"2023-06-16T04:00:00.000000Z"},"parent":{"uuid":"ceb37cbb-cccd-44fd-b309-82d863b25f9b","name":"Hemostasis/Thrombosis","type":"cdwg","status":"active"}}}

